"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([["3497"],{6856(n){n.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/vllm-architecture-lectures/docs/roadmap","label":"\u{1F5FA}\uFE0F Roadmap & Syllabus","docId":"roadmap","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_0_os_fundamentals","label":"B\xe0i 0: Ki\u1EBFn th\u1EE9c H\u1EC7 \u0111i\u1EC1u h\xe0nh b\u1ED5 tr\u1EE3","docId":"lesson_0_os_fundamentals","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_0_gpu_hardware","label":"B\xe0i 0.1: C\u1EA5u t\u1EA1o ph\u1EA7n c\u1EE9ng GPU & Prefill/Decode","docId":"lesson_0_gpu_hardware","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_1_memory_bottleneck","label":"B\xe0i 1: Autoregressive Serving & KV Cache","docId":"lesson_1_memory_bottleneck","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_2_paged_attention","label":"B\xe0i 2: PagedAttention & Block Allocation","docId":"lesson_2_paged_attention","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_3_continuous_batching","label":"B\xe0i 3: Continuous Batching & Preemption","docId":"lesson_3_continuous_batching","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_4_async_concurrency","label":"B\xe0i 4: Async Serving & Concurrency","docId":"lesson_4_async_concurrency","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_5_scheduler_code","label":"B\xe0i 5: Codebase: Scheduler & Block Manager","docId":"lesson_5_scheduler_code","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_6_distributed_worker","label":"B\xe0i 6: Codebase: Distributed Executor & Workers","docId":"lesson_6_distributed_worker","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_7_advanced_serving","label":"B\xe0i 7: K\u1EF9 thu\u1EADt T\u1ED1i \u01B0u h\xf3a N\xe2ng cao","docId":"lesson_7_advanced_serving","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_7_quantization_deep_dive","label":"B\xe0i 7.1: Chi ti\u1EBFt L\u01B0\u1EE3ng h\xf3a \u2013 AWQ vs Activation","docId":"lesson_7_quantization_deep_dive","unlisted":false},{"type":"link","href":"/vllm-architecture-lectures/docs/lesson_8_toy_serving_engine","label":"B\xe0i 8: Th\u1EF1c h\xe0nh Toy Serving Engine","docId":"lesson_8_toy_serving_engine","unlisted":false}]},"docs":{"lesson_0_gpu_hardware":{"id":"lesson_0_gpu_hardware","title":"B\xe0i 0.1: C\u1EA5u t\u1EA1o Ph\u1EA7n c\u1EE9ng GPU & B\u1EA3n ch\u1EA5t V\u1EADt l\xfd c\u1EE7a Prefill/Decode","description":"\u0110\u1EC3 t\u1ED1i \u01B0u h\xf3a ph\u1EA7n m\u1EC1m Serving, ta ph\u1EA3i hi\u1EC3u r\xf5 c\u01A1 c\u1EA5u ho\u1EA1t \u0111\u1ED9ng c\u1EE7a ph\u1EA7n c\u1EE9ng th\u1EF1c thi b\xean d\u01B0\u1EDBi \u2014 GPU. Trong b\xe0i h\u1ECDc n\xe0y, ch\xfang ta s\u1EBD ph\xe2n t\xedch ki\u1EBFn tr\xfac ph\u1EA7n c\u1EE9ng c\u1EE7a GPU (t\u1EEB SMs, Tensor Cores \u0111\u1EBFn ph\xe2n c\u1EA5p b\u1ED9 nh\u1EDB HBM/SRAM) v\xe0 d\xf9ng m\xf4 h\xecnh to\xe1n h\u1ECDc Roofline Model \u0111\u1EC3 gi\u1EA3i th\xedch b\u1EA3n ch\u1EA5t v\u1EADt l\xfd c\u1EE7a hai pha Prefill (Compute-bound) v\xe0 Decode (Memory-bound).","sidebar":"tutorialSidebar"},"lesson_0_os_fundamentals":{"id":"lesson_0_os_fundamentals","title":"B\xe0i 0: Ki\u1EBFn th\u1EE9c H\u1EC7 \u0111i\u1EC1u h\xe0nh b\u1ED5 tr\u1EE3 (OS Fundamentals for AI Serving)","description":"\u0110\u1EC3 hi\u1EC3u s\xe2u s\u1EAFc c\xe1c quy\u1EBFt \u0111\u1ECBnh thi\u1EBFt k\u1EBF ki\u1EBFn tr\xfac c\u1EE7a vLLM (nh\u01B0 PagedAttention, Decoupled Engine, Multi-processing Workers), ch\xfang ta c\u1EA7n trang b\u1ECB n\u1EC1n t\u1EA3ng ki\u1EBFn th\u1EE9c v\u1EEFng ch\u1EAFc v\u1EC1 H\u1EC7 \u0111i\u1EC1u h\xe0nh (Operating System - OS).","sidebar":"tutorialSidebar"},"lesson_1_memory_bottleneck":{"id":"lesson_1_memory_bottleneck","title":"B\xe0i 1: Autoregressive Serving & Th\xe1ch th\u1EE9c Qu\u1EA3n l\xfd B\u1ED9 nh\u1EDB (Memory Bottleneck)","description":"Trong b\xe0i h\u1ECDc \u0111\u1EA7u ti\xean n\xe0y, ch\xfang ta s\u1EBD ph\xe2n t\xedch t\u1EEB g\xf3c \u0111\u1ED9 h\u1EC7 th\u1ED1ng suy lu\u1EADn (Inference System) \u0111\u1EC3 hi\u1EC3u r\xf5 b\u1EA3n ch\u1EA5t to\xe1n h\u1ECDc v\xe0 v\u1EADt l\xfd \u0111\u1EB1ng sau nh\u1EEFng kh\xf3 kh\u0103n khi ch\u1EA1y m\xf4 h\xecnh ng\xf4n ng\u1EEF l\u1EDBn (LLM). T\u1EA1i sao vi\u1EC7c suy lu\u1EADn LLM l\u1EA1i ch\u1EADm? T\u1EA1i sao b\u1ED9 nh\u1EDB GPU lu\xf4n b\u1ECB c\u1EA1n ki\u1EC7t m\u1EB7c d\xf9 card \u0111\u1ED3 h\u1ECDa c\u1EE7a b\u1EA1n c\xf3 hi\u1EC7u n\u0103ng t\xednh to\xe1n kh\u1ED5ng l\u1ED3?","sidebar":"tutorialSidebar"},"lesson_2_paged_attention":{"id":"lesson_2_paged_attention","title":"B\xe0i 2: \u0110\u1ED9t ph\xe1 c\u1EE7a vLLM \u2013 Thu\u1EADt to\xe1n PagedAttention & C\u1EA5p ph\xe1t Kh\u1ED1i","description":"Trong b\xe0i 1, ch\xfang ta \u0111\xe3 hi\u1EC3u l\xfd do t\u1EA1i sao c\xe1c h\u1EC7 th\u1ED1ng ph\u1EE5c v\u1EE5 LLM truy\u1EC1n th\u1ED1ng b\u1ECB gi\u1EDBi h\u1EA1n b\u1EDFi v\u1EA5n \u0111\u1EC1 ph\xe2n m\u1EA3nh b\u1ED9 nh\u1EDB KV Cache. Trong b\xe0i n\xe0y, ch\xfang ta s\u1EBD ph\xe2n t\xedch gi\u1EA3i ph\xe1p mang t\xednh c\xe1ch m\u1EA1ng c\u1EE7a vLLM: PagedAttention. \u0110\xe2y l\xe0 ph\xe1t minh c\u1ED1t l\xf5i gi\xfap vLLM t\u0103ng n\u0103ng l\u1EF1c ph\u1EE5c v\u1EE5 g\u1EA5p h\xe0ng ch\u1EE5c l\u1EA7n b\u1EB1ng c\xe1ch t\u1ED1i \u01B0u h\xf3a tri\u1EC7t \u0111\u1EC3 kh\xf4ng gian b\u1ED9 nh\u1EDB GPU.","sidebar":"tutorialSidebar"},"lesson_3_continuous_batching":{"id":"lesson_3_continuous_batching","title":"B\xe0i 3: Chi\u1EBFn l\u01B0\u1EE3c L\u1EADp l\u1ECBch t\u1ED1i \u01B0u \u2013 Continuous Batching & Preemption","description":"Trong c\xe1c h\u1EC7 th\u1ED1ng Serving th\xf4ng th\u01B0\u1EDDng, \u0111\u1EC3 t\u0103ng b\u0103ng th\xf4ng (throughput), ch\xfang ta ph\u1EA3i gom nhi\u1EC1u request l\u1EA1i th\xe0nh m\u1ED9t l\xf4 (batch) tr\u01B0\u1EDBc khi \u0111\u1EA9y v\xe0o GPU. Tuy nhi\xean, suy lu\u1EADn LLM c\xf3 t\xednh ch\u1EA5t sinh token \u0111\u1ED9ng: m\u1ED7i request c\xf3 \u0111\u1ED9 d\xe0i prompt kh\xe1c nhau v\xe0 k\u1EBFt th\xfac \u1EDF c\xe1c b\u01B0\u1EDBc kh\xe1c nhau (do g\u1EB7p token `` ho\u1EB7c \u0111\u1EA1t gi\u1EDBi h\u1EA1n t\u1ED1i \u0111a).","sidebar":"tutorialSidebar"},"lesson_4_async_concurrency":{"id":"lesson_4_async_concurrency","title":"B\xe0i 4: Async Serving, Concurrency & Streaming (Ki\u1EBFn tr\xfac B\u1EA5t \u0111\u1ED3ng b\u1ED9 & X\u1EED l\xfd \u0110\u1ED3ng th\u1EDDi)","description":"M\u1ED9t h\u1EC7 th\u1ED1ng AI serving trong m\xf4i tr\u01B0\u1EDDng s\u1EA3n xu\u1EA5t (production) ph\u1EA3i \u0111\u1ED1i m\u1EB7t v\u1EDBi \xe1p l\u1EF1c x\u1EED l\xfd h\xe0ng tr\u0103m ho\u1EB7c h\xe0ng ng\xe0n request \u0111\u1ED3ng th\u1EDDi t\u1EEB nhi\u1EC1u ng\u01B0\u1EDDi d\xf9ng. Trong b\xe0i n\xe0y, ch\xfang ta s\u1EBD kh\u1EA3o s\xe1t c\xe1ch vLLM thi\u1EBFt k\u1EBF h\u1EC7 th\u1ED1ng l\u1EADp tr\xecnh b\u1EA5t \u0111\u1ED3ng b\u1ED9 (asyncio) v\xe0 ki\u1EBFn tr\xfac t\xe1ch bi\u1EC7t (Decoupled Engine) \u1EDF phi\xean b\u1EA3n vLLM v1 m\u1EDBi nh\u1EA5t \u0111\u1EC3 \u0111\u1EA1t \u0111\u01B0\u1EE3c kh\u1EA3 n\u0103ng x\u1EED l\xfd \u0111\u1ED3ng th\u1EDDi c\u1EF1c cao m\xe0 kh\xf4ng l\xe0m ngh\u1EBDn ti\u1EBFn tr\xecnh t\xednh to\xe1n c\u1EE7a GPU.","sidebar":"tutorialSidebar"},"lesson_5_scheduler_code":{"id":"lesson_5_scheduler_code","title":"B\xe0i 5: Deep Dive Codebase \u2013 B\u1ED9 l\u1EADp l\u1ECBch Scheduler, Request Queue & Block Manager","description":"Trong c\xe1c b\xe0i h\u1ECDc tr\u01B0\u1EDBc, ch\xfang ta \u0111\xe3 n\u1EAFm v\u1EEFng c\xe1c kh\xe1i ni\u1EC7m l\xfd thuy\u1EBFt c\u1ED1t l\xf5i c\u1EE7a vLLM. T\u1EEB b\xe0i h\u1ECDc n\xe0y, ch\xfang ta s\u1EBD tr\u1EF1c ti\u1EBFp \u0111i s\xe2u v\xe0o chi ti\u1EBFt hi\u1EC7n th\u1EF1c trong m\xe3 ngu\u1ED3n vLLM v1. Ch\xfang ta s\u1EBD c\xf9ng nhau b\xf3c t\xe1ch c\xe1ch ho\u1EA1t \u0111\u1ED9ng c\u1EE7a ba c\u1EA5u ph\u1EA7n c\u1ED1t l\xf5i: B\u1ED9 qu\u1EA3n l\xfd h\xe0ng \u0111\u1EE3i y\xeau c\u1EA7u (RequestQueue), B\u1ED9 l\u1EADp l\u1ECBch (Scheduler), v\xe0 B\u1ED9 qu\u1EA3n l\xfd KV Cache (KVCacheManager).","sidebar":"tutorialSidebar"},"lesson_6_distributed_worker":{"id":"lesson_6_distributed_worker","title":"B\xe0i 6: Deep Dive Codebase \u2013 Distributed Executor & GPU Workers","description":"Khi ph\u1EE5c v\u1EE5 c\xe1c m\xf4 h\xecnh ng\xf4n ng\u1EEF l\u1EDBn (LLM) c\xf3 h\xe0ng ch\u1EE5c hay h\xe0ng tr\u0103m t\u1EF7 tham s\u1ED1 (nh\u01B0 Llama 3 70B, Mixtral 8x22B), b\u1EA3n th\xe2n tr\u1ECDng s\u1ED1 m\xf4 h\xecnh \u0111\xe3 v\u01B0\u1EE3t qu\xe1 dung l\u01B0\u1EE3ng VRAM c\u1EE7a m\u1ED9t GPU \u0111\u01A1n l\u1EBB (v\xed d\u1EE5 80GB c\u1EE7a GPU A100/H100). Do \u0111\xf3, h\u1EC7 th\u1ED1ng AI Serving b\u1EAFt bu\u1ED9c ph\u1EA3i h\u1ED7 tr\u1EE3 suy lu\u1EADn ph\xe2n t\xe1n (Distributed Inference).","sidebar":"tutorialSidebar"},"lesson_7_advanced_serving":{"id":"lesson_7_advanced_serving","title":"B\xe0i 7: K\u1EF9 thu\u1EADt T\u1ED1i \u01B0u h\xf3a N\xe2ng cao cho AI Serving","description":"B\xean c\u1EA1nh c\xe1c c\u01A1 ch\u1EBF ph\xe2n trang b\u1ED9 nh\u1EDB (PagedAttention) v\xe0 l\u1EADp l\u1ECBch th\xf4ng minh (Continuous Batching), vLLM c\xf2n t\xedch h\u1EE3p nhi\u1EC1u k\u1EF9 thu\u1EADt t\u1ED1i \u01B0u h\xf3a ti\xean ti\u1EBFn nh\u1EA5t trong nghi\xean c\u1EE9u h\u1EC7 th\u1ED1ng h\u1ECDc s\xe2u \u0111\u1EC3 t\u0103ng t\u1ED1c \u0111\u1ED9 suy lu\u1EADn v\xe0 ti\u1EBFt ki\u1EC7m t\xe0i nguy\xean. Trong b\xe0i h\u1ECDc n\xe0y, ch\xfang ta s\u1EBD kh\u1EA3o s\xe1t ba k\u1EF9 thu\u1EADt n\xe2ng cao: Speculative Decoding, Multi-LoRA Serving, v\xe0 c\xe1c \u0111\u1ECBnh d\u1EA1ng l\u01B0\u1EE3ng h\xf3a b\u1ED9 nh\u1EDB (Quantization).","sidebar":"tutorialSidebar"},"lesson_7_quantization_deep_dive":{"id":"lesson_7_quantization_deep_dive","title":"B\xe0i 7.1: Chi ti\u1EBFt L\u01B0\u1EE3ng h\xf3a \u2013 Weight-Only (AWQ) vs Activation Quantization","description":"L\u01B0\u1EE3ng h\xf3a (Quantization) l\xe0 m\u1ED9t trong nh\u1EEFng v\u0169 kh\xed t\u1ED1i th\u01B0\u1EE3ng c\u1EE7a AI Serving Engineer \u0111\u1EC3 n\xe9n m\xf4 h\xecnh v\xe0 t\u0103ng t\u1ED1c \u0111\u1ED9 suy lu\u1EADn. Tuy nhi\xean, vi\u1EC7c \xe1p d\u1EE5ng l\u01B0\u1EE3ng h\xf3a kh\xf4ng \u0111\u01A1n thu\u1EA7n l\xe0 l\xe0m tr\xf2n s\u1ED1. Ch\xfang ta c\u1EA7n hi\u1EC3u r\xf5 s\u1EF1 kh\xe1c bi\u1EC7t b\u1EA3n ch\u1EA5t gi\u1EEFa Weight-Only Quantization (nh\u01B0 AWQ) v\xe0 Activation Quantization (nh\u01B0 W8A8 ho\u1EB7c FP8) \u0111\u1EC3 ch\u1ECDn gi\u1EA3i ph\xe1p ph\xf9 h\u1EE3p nh\u1EA5t cho h\u1EC7 th\u1ED1ng ph\u1EE5c v\u1EE5 c\u1EE7a m\xecnh.","sidebar":"tutorialSidebar"},"lesson_8_toy_serving_engine":{"id":"lesson_8_toy_serving_engine","title":"B\xe0i 8: Thi\u1EBFt k\u1EBF h\u1EC7 th\u1ED1ng Toy Serving Engine t\u1ED1i gi\u1EA3n","description":"Ch\xe0o m\u1EEBng b\u1EA1n \u0111\u1EBFn v\u1EDBi b\xe0i h\u1ECDc cu\u1ED1i c\xf9ng! \u1EDE c\xe1c b\xe0i h\u1ECDc tr\u01B0\u1EDBc, ch\xfang ta \u0111\xe3 t\xedch l\u0169y \u0111\u1EA7y \u0111\u1EE7 ki\u1EBFn th\u1EE9c l\xfd thuy\u1EBFt v\u1EC1 c\xe1ch vLLM ho\u1EA1t \u0111\u1ED9ng. \u0110\u1EC3 chuy\u1EC3n h\xf3a l\xfd thuy\u1EBFt th\xe0nh k\u1EF9 n\u0103ng th\u1EF1c ti\u1EC5n, trong b\xe0i n\xe0y ch\xfang ta s\u1EBD c\xf9ng nhau thi\u1EBFt k\u1EBF v\xe0 hi\u1EC7n th\u1EF1c m\u1ED9t Toy Serving Engine t\u1ED1i gi\u1EA3n vi\u1EBFt b\u1EB1ng Python.","sidebar":"tutorialSidebar"},"roadmap":{"id":"roadmap","title":"vLLM Internals: Deep Dive into LLM Serving Architecture","description":"Ch\xe0o m\u1EEBng b\u1EA1n \u0111\u1EBFn v\u1EDBi kho l\u01B0u tr\u1EEF b\xe0i gi\u1EA3ng vLLM Internals: Deep Dive into LLM Serving Architecture. Chu\u1ED7i b\xe0i gi\u1EA3ng n\xe0y \u0111\u01B0\u1EE3c thi\u1EBFt k\u1EBF \u0111\u1EB7c bi\u1EC7t cho c\xe1c AI Serving Engineer, Deep Learning Engineer v\xe0 Research Engineer mu\u1ED1n t\xecm hi\u1EC3u s\xe2u s\u1EAFc v\u1EC1 c\xe1ch th\u1EE9c ho\u1EA1t \u0111\u1ED9ng b\xean trong c\u1EE7a vLLM \u2014 th\u01B0 vi\u1EC7n ph\u1EE5c v\u1EE5 m\xf4 h\xecnh ng\xf4n ng\u1EEF l\u1EDBn (LLM Serving) ph\u1ED5 bi\u1EBFn v\xe0 t\u1ED1i \u01B0u nh\u1EA5t hi\u1EC7n nay.","sidebar":"tutorialSidebar"}}}}')}}]);